static const float x2_b_1[16] = {0.00581869f, -0.01090997f, 0.03219544f, -0.01218127f, 0.01000465f, 0.01777508f, -0.00343580f, -0.00183976f, -0.00175720f, 0.00000000f, -0.00900672f, -0.01238283f, -0.02071865f, 0.00192099f, -0.02943675f, -0.00580197f};

